import{_ as t,c as n,o as r,ah as o}from"./chunks/framework.RCw5T9E9.js";const u=JSON.parse('{"title":"Advanced capture mode","description":"","frontmatter":{"title":"Advanced capture mode"},"headers":[],"relativePath":"network/advanced.md","filePath":"network/advanced.md"}'),s={name:"network/advanced.md"};function a(d,e,i,l,h,g){return r(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="advanced-capture-mode" tabindex="-1">Advanced capture mode <a class="header-anchor" href="#advanced-capture-mode" aria-label="Permalink to &quot;Advanced capture mode&quot;">​</a></h1><p>Under <strong>Options → Network</strong> you can choose the <strong>capture mode</strong> for network traffic:</p><table tabindex="0"><thead><tr><th>Mode</th><th>In the UI</th><th>What it means</th></tr></thead><tbody><tr><td><strong>Classic mode</strong></td><td>classic snapshot</td><td>Same limits as in-page interception: headers and bodies are only what page scripts can read (including <strong>CORS</strong> rules for cross-origin). See <a href="./general.html#display-limits">Working with requests</a>.</td></tr><tr><td><strong>Advanced mode</strong></td><td>extended capture</td><td>The extension requests <strong><code>webRequest</code></strong> access and enriches the request details with the <strong>full set</strong> of request and response headers as seen by the browser for the exchange—not only the subset exposed to the page.</td></tr></tbody></table><p><strong>Advanced mode</strong> (pinning headers, <strong>Header links</strong>, Advanced-only header visibility options) is available <strong>only in the Chrome / Edge extension</strong>.<br><strong>Standalone</strong> still runs without extended capture: the full header set via <strong><code>webRequest</code></strong> described below <strong>is not available</strong> there.</p><hr><h2 id="what-advanced-mode-adds-in-the-network-tab" tabindex="-1">What Advanced mode adds in the Network tab <a class="header-anchor" href="#what-advanced-mode-adds-in-the-network-tab" aria-label="Permalink to &quot;What Advanced mode adds in the Network tab&quot;">​</a></h2><ul><li><strong>Request and response headers</strong> in request details use the extended data (including headers not listed in <code>Access-Control-Expose-Headers</code>).</li><li><strong>Pinning header rows</strong> — a header name can be pinned <strong>to the top of the list</strong> separately for <strong>Request</strong> and <strong>Response</strong>. Pins are toggled from the <strong>row menu</strong> (three dots) when Advanced mode is on.</li><li><strong>Header links</strong> — for a given header name and request <strong>Host</strong>, open an external URL using a template; <strong><code>{value}</code></strong> is replaced with the header value as shown in Network.</li></ul><p>The <strong>Header links</strong> list, <strong>Pinned headers</strong> table, and <strong>Advanced headers</strong> options under <strong>Options → Network</strong> are shown <strong>only when Advanced mode is enabled</strong>, so Classic mode stays uncluttered.</p><hr><h2 id="header-links" tabindex="-1">Header links <a class="header-anchor" href="#header-links" aria-label="Permalink to &quot;Header links&quot;">​</a></h2><p>Each rule defines:</p><ul><li><strong>Header</strong> — HTTP header name (matched <strong>case-insensitively</strong>);</li><li><strong>Host</strong> — host of the request URL (normalized: no scheme or path, e.g. <code>api.example.com</code>);</li><li><strong>Link</strong> — URL template; <strong><code>{value}</code></strong> is replaced with the raw header value from the request card.</li></ul><p>You can create and edit rules from the <strong>header row menu</strong> on the <strong>Network</strong> tab (Advanced) and from <strong>Options</strong> when a header rule group is selected.</p><hr><h2 id="quick-recap" tabindex="-1">Quick recap <a class="header-anchor" href="#quick-recap" aria-label="Permalink to &quot;Quick recap&quot;">​</a></h2><ul><li><strong>Advanced mode</strong> extends headers via <strong><code>webRequest</code></strong>; <strong>Standalone</strong> does not provide this mode.</li><li><strong>Classic mode</strong> is the original “page-visible” header model.</li><li><strong>Pin</strong> — separate for <strong>Request</strong> / <strong>Response</strong> lists.</li><li><strong>Header links:</strong> <strong>Host</strong> + <strong>Link</strong> template with <strong><code>{value}</code></strong> for the header value.</li></ul>',16)])])}const p=t(s,[["render",a]]);export{u as __pageData,p as default};
